+      log_kind = Log::Kind::Error;
+      break;
+    default:
+      RCUTILS_LOG_ERROR("Unknown logging severity type %d", severity);
+      return RMW_RET_ERROR;
+  }
+
+  eprosima::fastrtps::Log::SetVerbosity(log_kind);
+
+  return RMW_RET_OK;
+}
