+                    break;
+                case ::rosidl_typesupport_introspection_cpp::ROS_TYPE_BYTE:
+                case ::rosidl_typesupport_introspection_cpp::ROS_TYPE_UINT8:
+                    ser.serializeArray((uint8_t*)field, member->array_size_);
